import{_ as a,o as i,c as t,ag as r}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"QiAccess Start Master Blueprint","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/readme.md","filePath":"10_core/readme.md"}'),l={name:"10_core/readme.md"};function o(n,e,s,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="qiaccess-start-master-blueprint" tabindex="-1">QiAccess Start Master Blueprint <a class="header-anchor" href="#qiaccess-start-master-blueprint" aria-label="Permalink to &quot;QiAccess Start Master Blueprint&quot;">​</a></h1><p>This repository is the active master blueprint for QiAccess Start.</p><p>QiAccess Start is Cody&#39;s cognitive front door:</p><ol><li>Home</li><li>Start</li><li>Capture</li><li>Knowledge</li><li>Memory</li><li>Insights</li><li>System</li></ol><p>The old QiOS material is not discarded, but it is no longer allowed to compete with the active doctrine. Useful governance, standards, registry discipline, and architecture policies remain in force. Legacy multi-tenant and client-platform assumptions are retained only as quarantined reference material until they are explicitly revalidated.</p><h2 id="active-doctrine" tabindex="-1">Active Doctrine <a class="header-anchor" href="#active-doctrine" aria-label="Permalink to &quot;Active Doctrine&quot;">​</a></h2><ul><li>QiAccess is the portal.</li><li>The map is the interface.</li><li>The knowledge base is the memory behind each node.</li><li>Capture must stay fast or the system fails.</li><li>System is nested administration, not a top-level junk drawer.</li><li>Memory and Insights stay honest when they are placeholders.</li></ul><h2 id="current-phase" tabindex="-1">Current Phase <a class="header-anchor" href="#current-phase" aria-label="Permalink to &quot;Current Phase&quot;">​</a></h2><p>Phase 1 remains stabilization and prototype flow validation:</p><ol><li>keep the SPA working</li><li>align the app to the seven roots</li><li>preserve working launcher and link behavior</li><li>freeze legacy surfaces in place</li><li>validate Capture as the first real operating path</li></ol><h2 id="what-stays-authoritative" tabindex="-1">What Stays Authoritative <a class="header-anchor" href="#what-stays-authoritative" aria-label="Permalink to &quot;What Stays Authoritative&quot;">​</a></h2><ul><li><code>docs/01_governance/</code>: principles, policies, registry, and ADR discipline</li><li><code>docs/02_architecture/</code>: active QiAccess Start system model and runtime framing</li><li><code>docs/06_applications/</code>: the seven-root portal doctrine</li><li><code>docs/08_appendices/20_legacy/</code>: quarantined legacy material and salvage notes</li><li><code>standards/</code> and <code>registry/</code>: retained structural controls that still serve the active system</li></ul><h2 id="build-loop" tabindex="-1">Build Loop <a class="header-anchor" href="#build-loop" aria-label="Permalink to &quot;Build Loop&quot;">​</a></h2><p>The blueprint can still be maintained through the existing documentation toolchain:</p><ol><li>update doctrine or registry files</li><li>run <code>rebuild.bat</code></li><li>inspect validation output</li><li>preview with <code>mkdocs serve</code> when needed</li></ol><h2 id="legacy-handling" tabindex="-1">Legacy Handling <a class="header-anchor" href="#legacy-handling" aria-label="Permalink to &quot;Legacy Handling&quot;">​</a></h2><p>Use the quarantine appendix before promoting older QiOS, QiOne, tenant, client, or product-delivery doctrine back into the active blueprint:</p><ul><li><code>docs/08_appendices/20_legacy/legacy_salvage.md</code></li><li><code>docs/08_appendices/20_legacy/qiaccess_start_legacy_quarantine.md</code></li></ul>',18)])])}const m=a(l,[["render",o]]);export{u as __pageData,m as default};
